import static org.junit.jupiter.api.Assertions.*;
import java.lang.reflect.Method;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private static Method isLineBreakCharMethod;
    private static Method isLineBreakCharacterMethod;

    @BeforeAll
    public static void setUp() throws Exception {
        // Access private static method isLineBreak(char)
        isLineBreakCharMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        isLineBreakCharMethod.setAccessible(true);
        // Access private static method isLineBreak(Character)
        isLineBreakCharacterMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakCharacterMethod.setAccessible(true);
    }

    @Test
    public void testIsLineBreakWithChar_LF() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, '\n'); // LF
        assertTrue(result);
    }

    @Test
    public void testIsLineBreakWithChar_CR() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, '\r'); // CR
        assertTrue(result);
    }

    @Test
    public void testIsLineBreakWithChar_Other() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, 'a');
        assertFalse(result);
        result = (boolean) isLineBreakCharMethod.invoke(null, '\t');
        assertFalse(result);
        result = (boolean) isLineBreakCharMethod.invoke(null, ' ');
        assertFalse(result);
    }

    @Test
    public void testIsLineBreakWithCharacter_Null() throws Exception {
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, (Character) null);
        assertFalse(result);
    }

    @Test
    public void testIsLineBreakWithCharacter_LF() throws Exception {
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, '\n');
        assertTrue(result);
    }

    @Test
    public void testIsLineBreakWithCharacter_CR() throws Exception {
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, '\r');
        assertTrue(result);
    }

    @Test
    public void testIsLineBreakWithCharacter_Other() throws Exception {
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, 'x');
        assertFalse(result);
        result = (Boolean) isLineBreakCharacterMethod.invoke(null, '\t');
        assertFalse(result);
    }
}
